import React, { useRef, useEffect, useCallback } from 'react';

// ─── Constants ────────────────────────────────────────────────────────────────
const CHUNK_BYTES      = 4 * 1024 * 1024;   // 4 MB per chunk
const PREFETCH_AHEAD   = 2;                  // keep N chunks ahead in buffer
const DRIFT_THRESHOLD  = 0.08;              // seconds before we resync audio
const SYNC_INTERVAL_MS = 500;               // drift-check interval
const MIME_CODEC       = 'video/mp4; codecs="avc1.42E01E,mp4a.40.2"';

// ─── Chunk Fetcher ────────────────────────────────────────────────────────────
async function fetchChunk(url, start, end, signal) {
  const res = await fetch(url, {
    headers: { Range: `bytes=${start}-${end}` },
    signal,
  });
  if (!res.ok && res.status !== 206) throw new Error(`HTTP ${res.status}`);
  return res.arrayBuffer();
}

async function getContentLength(url, signal) {
  const res = await fetch(url, { method: 'HEAD', signal });
  const len = parseInt(res.headers.get('content-length') || '0', 10);
  return len;
}

// ─── MSE Streaming Engine ─────────────────────────────────────────────────────
class StreamEngine {
  constructor(videoEl, src) {
    this.videoEl    = videoEl;
    this.src        = src;
    this.ms         = new MediaSource();
    this.sb         = null;
    this.totalBytes = 0;
    this.nextByte   = 0;
    this.chunkIndex = 0;
    this.fetching   = false;
    this.destroyed  = false;
    this.ac         = new AbortController();
    this.readyPromise = new Promise(res => { this._resolveReady = res; });
  }

  start() {
    this.videoEl.src = URL.createObjectURL(this.ms);
    this.ms.addEventListener('sourceopen', () => this._onSourceOpen(), { once: true });
    return this.readyPromise;   // resolves when first chunk is appended
  }

  async _onSourceOpen() {
    if (!MediaSource.isTypeSupported(MIME_CODEC)) {
      // Fallback: let browser handle it natively
      this.videoEl.src = this.src;
      this._resolveReady();
      return;
    }
    this.sb = this.ms.addSourceBuffer(MIME_CODEC);
    this.sb.mode = 'sequence';
    this.sb.addEventListener('updateend', () => this._pump());

    try {
      this.totalBytes = await getContentLength(this.src, this.ac.signal);
    } catch { this.totalBytes = 0; }

    this._pump();
  }

  _pump() {
    if (this.destroyed || this.fetching || !this.sb) return;
    if (this.totalBytes && this.nextByte >= this.totalBytes) {
      if (!this.sb.updating && this.ms.readyState === 'open') this.ms.endOfStream();
      return;
    }
    // Only prefetch PREFETCH_AHEAD chunks beyond what video has buffered
    const buffered = this.videoEl.buffered.length
      ? this.videoEl.buffered.end(this.videoEl.buffered.length - 1)
      : 0;
    const currentTime = this.videoEl.currentTime;
    if (buffered - currentTime > PREFETCH_AHEAD * 8) return;  // ~8s per chunk

    this._fetchNext();
  }

  async _fetchNext() {
    this.fetching = true;
    const start = this.nextByte;
    const end   = this.totalBytes
      ? Math.min(start + CHUNK_BYTES - 1, this.totalBytes - 1)
      : start + CHUNK_BYTES - 1;

    try {
      const buf = await fetchChunk(this.src, start, end, this.ac.signal);
      if (this.destroyed || !this.sb) return;
      this.nextByte = end + 1;
      this.chunkIndex++;
      this.sb.appendBuffer(buf);
      if (this.chunkIndex === 1) this._resolveReady();   // first chunk ready
    } catch (e) {
      if (!this.destroyed) console.warn('[StreamEngine] fetch error', e);
    } finally {
      this.fetching = false;
    }
  }

  // Called by player on timeupdate to keep buffer ahead
  onTimeUpdate() { this._pump(); }

  destroy() {
    this.destroyed = true;
    this.sb = null;
    this.ac.abort();
    try { if (this.ms.readyState === 'open') this.ms.endOfStream(); } catch {}
    URL.revokeObjectURL(this.videoEl.src);
  }
}

// ─── Component ────────────────────────────────────────────────────────────────
const VideoAudioPlayer = ({ src, id, activeAudioId, onVisibilityChange }) => {
  const videoRef     = useRef(null);
  const audioRef     = useRef(null);
  const containerRef = useRef(null);
  const engineRef    = useRef(null);
  const syncTimerRef = useRef(null);
  const isActive     = activeAudioId === id;
  const audioSrc     = src.replace(/\.(mp4|webm)(\?.*)?$/i, '.mp3$2');

  // ── Drift correction loop ──────────────────────────────────────────────────
  const startSyncLoop = useCallback(() => {
    clearInterval(syncTimerRef.current);
    syncTimerRef.current = setInterval(() => {
      const v = videoRef.current;
      const a = audioRef.current;
      if (!v || !a || v.paused || a.paused) return;
      const drift = Math.abs(v.currentTime - a.currentTime);
      if (drift > DRIFT_THRESHOLD) {
        a.currentTime = v.currentTime;
      }
    }, SYNC_INTERVAL_MS);
  }, []);

  const stopSyncLoop = useCallback(() => {
    clearInterval(syncTimerRef.current);
  }, []);

  // ── MSE engine bootstrap ───────────────────────────────────────────────────
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const supportsRangeAndMSE =
      typeof MediaSource !== 'undefined' &&
      MediaSource.isTypeSupported(MIME_CODEC);

    if (supportsRangeAndMSE) {
      const engine = new StreamEngine(video, src);
      engineRef.current = engine;

      engine.start().then(() => {
        video.play().catch(() => {});
      });

      const onTimeUpdate = () => engine.onTimeUpdate();
      video.addEventListener('timeupdate', onTimeUpdate);
      engine._removeTimeUpdate = () => video.removeEventListener('timeupdate', onTimeUpdate);
    } else {
      // Graceful fallback for browsers without MSE / Range support
      video.src = src;
      video.play().catch(() => {});
    }

    return () => {
      engineRef.current?._removeTimeUpdate?.();
      engineRef.current?.destroy();
      engineRef.current = null;
    };
  }, [src]);

  // ── Active audio control + sync ────────────────────────────────────────────
  useEffect(() => {
    const audio = audioRef.current;
    const video = videoRef.current;
    if (!audio || !video) return;

    if (isActive) {
      audio.currentTime = video.currentTime;
      audio.play().catch(() => {});
      startSyncLoop();
    } else {
      audio.pause();
      stopSyncLoop();
    }

    return () => stopSyncLoop();
  }, [isActive, startSyncLoop, stopSyncLoop]);

  // ── Intersection observer ──────────────────────────────────────────────────
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const observer = new IntersectionObserver(
      ([entry]) => onVisibilityChange(id, entry.isIntersecting && entry.intersectionRatio > 0.5),
      { threshold: 0.5 }
    );
    observer.observe(container);
    return () => observer.disconnect();
  }, [id, onVisibilityChange]);

  return (
    <div ref={containerRef} style={{ overflowAnchor: 'none' }}>
      <video
        ref={videoRef}
        autoPlay
        loop
        muted
        playsInline
        style={{ width: '100%', height: 'auto', display: 'block' }}
      />
      <audio
        ref={audioRef}
        src={audioSrc}
        loop
        style={{ position: 'absolute', left: '-9999px' }}
        tabIndex="-1"
      />
    </div>
  );
};

export default VideoAudioPlayer;
